INSERT INTO workflow_entity ("id", "name", "nodes", "connections", "active", "createdAt", "updatedAt", "settings", "versionCounter", "versionId", "triggerCount", "isArchived") VALUES ('88ec9823-3b4e-4f1e-8b1e-1e1e1e1e1e01', '01 — RC iCal Sync', '[{"id": "t1", "name": "Every 30 Minutes", "type": "n8n-nodes-base.scheduleTrigger", "typeVersion": 1.2, "parameters": {"rule": {"interval": [{"field": "minutes", "minutesInterval": 30}]}}, "position": [100, 300]}, {"id": "s1", "name": "Apartments", "type": "n8n-nodes-base.code", "typeVersion": 2, "parameters": {"jsCode": "return [{\"id\":\"40\",\"lot\":\"302043\",\"name\":\"\u041d\u043e\u043c\u0435\u0440 40\",\"base_price\":4000},{\"id\":\"41\",\"lot\":\"302052\",\"name\":\"\u041d\u043e\u043c\u0435\u0440 41\",\"base_price\":4500},{\"id\":\"42\",\"lot\":\"310322\",\"name\":\"\u041d\u043e\u043c\u0435\u0440 42\",\"base_price\":4500},{\"id\":\"50\",\"lot\":\"310313\",\"name\":\"\u041d\u043e\u043c\u0435\u0440 50\",\"base_price\":7000}].map(a=>({json:a}));"}, "position": [300, 300]}, {"id": "f1", "name": "Fetch iCal", "type": "n8n-nodes-base.httpRequest", "typeVersion": 4.2, "parameters": {"method": "GET", "url": "=https://realtycalendar.ru/ical/{{ json.lot }}.ics", "options": {"response": {"response": {"responseFormat": "text"}}, "timeout": 30000}}, "position": [500, 300], "onError": "continueRegularOutput"}, {"id": "p1", "name": "Parse", "type": "n8n-nodes-base.code", "typeVersion": 2, "parameters": {"jsCode": "const t=input.first().json.data||'''';if(!t||t.length<20)return[{json:{events:[],count:0}}];const l=t.split(''\\n''),e=[];let c={};for(const x of l){const s=x.trim();if(s===''BEGIN:VEVENT'')c={};if(s.startsWith(''DTSTART''))c.start=s.split('':'').pop().substring(0,8);if(s.startsWith(''DTEND''))c.end=s.split('':'').pop().substring(0,8);if(s.startsWith(''SUMMARY''))c.summary=s.split('':'').slice(1).join('':'');if(s===''END:VEVENT''&&c.start)e.push({...c})}return[{json:{events:e,count:e.length}}];"}, "position": [700, 300]}]', '{"Every 30 Minutes": {"main": [[{"node": "Apartments", "type": "main", "index": 0}]]}, "Apartments": {"main": [[{"node": "Fetch iCal", "type": "main", "index": 0}]]}, "Fetch iCal": {"main": [[{"node": "Parse", "type": "main", "index": 0}]]}}', false, NOW(), NOW(), '{"executionOrder": "v1"}', 1, '822e15f3-e08f-4eeb-ba83-a1f98a958f74', 0, false);
INSERT INTO workflow_entity ("id", "name", "nodes", "connections", "active", "createdAt", "updatedAt", "settings", "versionCounter", "versionId", "triggerCount", "isArchived") VALUES ('88ec9823-3b4e-4f1e-8b1e-1e1e1e1e1e02', '02 — Owner Bot (Voice + Claude)', '[{"parameters": {"updates": ["message"], "additionalFields": {}}, "id": "t1", "name": "Telegram Trigger", "type": "n8n-nodes-base.telegramTrigger", "typeVersion": 1, "position": [100, 300], "credentials": {"telegramApi": {"id": "telegram_owner_bot"}}}, {"parameters": {"conditions": {"boolean": [{"value1": "={{ !!$json.message.voice }}", "value2": true}]}}, "id": "s1", "name": "Is Voice?", "type": "n8n-nodes-base.if", "typeVersion": 1, "position": [300, 300]}, {"parameters": {"method": "POST", "url": "http://gelendzhik-whisper:9000/asr", "sendQueryParameters": true, "queryParameters": {"parameters": [{"name": "task", "value": "transcribe"}, {"name": "language", "value": "ru"}, {"name": "output", "value": "json"}]}, "sendBody": true, "contentType": "multipart-form-data", "bodyParameters": {"parameters": [{"parameterType": "formBinaryData", "name": "audio_file", "inputDataFieldName": "data"}]}, "options": {}}, "id": "w1", "name": "Whisper STT", "type": "n8n-nodes-base.httpRequest", "typeVersion": 4.1, "position": [500, 200]}, {"parameters": {"modelId": "claude-3-5-sonnet-20240620", "messages": {"message": [{"role": "system", "content": "={{ $node[\"Read Prompt\"].json.prompt }}"}, {"content": "={{ $json.message.text || $node[\"Whisper STT\"].json.text }}"}]}, "options": {"maxTokens": 1000, "temperature": 0.7}}, "id": "cl1", "name": "Claude AI", "type": "n8n-nodes-base.anthropicChat", "typeVersion": 1, "position": [750, 300], "credentials": {"anthropicApi": {"id": "anthropic_key"}}}, {"parameters": {"chatId": "={{ $node[\"Telegram Trigger\"].json.message.chat.id }}", "text": "={{ $json.content[0].text }}", "additionalFields": {}}, "id": "r1", "name": "Send Reply", "type": "n8n-nodes-base.telegram", "typeVersion": 1.1, "position": [950, 300], "credentials": {"telegramApi": {"id": "telegram_owner_bot"}}}]', '{"Telegram Trigger": {"main": [[{"node": "Is Voice?", "type": "main", "index": 0}]]}, "Is Voice?": {"main": [[{"node": "Whisper STT", "type": "main", "index": 0}], [{"node": "Claude AI", "type": "main", "index": 0}]]}, "Whisper STT": {"main": [[{"node": "Claude AI", "type": "main", "index": 0}]]}, "Claude AI": {"main": [[{"node": "Send Reply", "type": "main", "index": 0}]]}}', false, NOW(), NOW(), '{}', 1, '45a18697-507e-48b7-8394-827135d8308f', 0, false);
INSERT INTO workflow_entity ("id", "name", "nodes", "connections", "active", "createdAt", "updatedAt", "settings", "versionCounter", "versionId", "triggerCount", "isArchived") VALUES ('88ec9823-3b4e-4f1e-8b1e-1e1e1e1e1e03', '03 — Guest Journey (Automated Touchpoints)', '[{"parameters": {"rule": {"interval": [{"field": "hours", "hoursInterval": 1}]}}, "id": "t1", "name": "Hourly Check", "type": "n8n-nodes-base.scheduleTrigger", "typeVersion": 1.2, "position": [100, 300]}, {"parameters": {"operation": "executeQuery", "query": "SELECT * FROM bookings WHERE status = ''confirmed'';"}, "id": "db1", "name": "Get Bookings", "type": "n8n-nodes-base.postgresDb", "typeVersion": 1, "position": [300, 300], "credentials": {"postgresDb": {"id": "gelendzhik_db"}}}, {"parameters": {"jsCode": "const now = new Date();\nreturn input.all().map(item => {\n  const checkin = new Date(item.json.checkin_date);\n  const daysTo = Math.ceil((checkin - now) / 86400000);\n  item.json.days_to_checkin = daysTo;\n  return item;\n});"}, "id": "c1", "name": "Calculate Days", "type": "n8n-nodes-base.code", "typeVersion": 2, "position": [500, 300]}, {"parameters": {"chatId": "={{ $json.guest_chat_id }}", "text": "={{ $node[\"Messages\"].json.text }}", "additionalFields": {}}, "id": "r1", "name": "Send Guest Bot", "type": "n8n-nodes-base.telegram", "typeVersion": 1.1, "position": [800, 300], "credentials": {"telegramApi": {"id": "telegram_guest_bot"}}}]', '{"Hourly Check": {"main": [[{"node": "Get Bookings", "type": "main", "index": 0}]]}, "Get Bookings": {"main": [[{"node": "Calculate Days", "type": "main", "index": 0}]]}}', false, NOW(), NOW(), '{}', 1, '90280314-7b54-4b29-ae00-1dcdadb73e77', 0, false);
INSERT INTO workflow_entity ("id", "name", "nodes", "connections", "active", "createdAt", "updatedAt", "settings", "versionCounter", "versionId", "triggerCount", "isArchived") VALUES ('88ec9823-3b4e-4f1e-8b1e-1e1e1e1e1e04', '04 — Daily Pricing (Auto-Update RC)', '[{"parameters": {"rule": {"interval": [{"field": "hours", "hoursInterval": 24}]}}, "id": "t1", "name": "Daily 06:00", "type": "n8n-nodes-base.scheduleTrigger", "typeVersion": 1.2, "position": [100, 300]}, {"parameters": {"jsCode": "return [\n  { id: ''40'', base: 4000, lot: ''302043'' },\n  { id: ''41'', base: 4500, lot: ''302052'' },\n  { id: ''42'', base: 4500, lot: ''310322'' },\n  { id: ''50'', base: 7000, lot: ''310313'' }\n].map(a => ({ json: a }));"}, "id": "s1", "name": "Property Data", "type": "n8n-nodes-base.code", "typeVersion": 2, "position": [300, 300]}, {"parameters": {"method": "POST", "url": "https://realtycalendar.ru/api/v1/lots/{{$json.lot}}/prices", "sendBody": true, "bodyParameters": {"parameters": [{"name": "prices", "value": "={{ $node[\"Pricing Logic\"].json.prices_obj }}"}]}, "options": {}}, "id": "h1", "name": "Update RC", "type": "n8n-nodes-base.httpRequest", "typeVersion": 4.2, "position": [700, 300], "credentials": {"httpHeaderAuth": {"id": "realty_calendar_v1"}}}]', '{"Daily 06:00": {"main": [[{"node": "Property Data", "type": "main", "index": 0}]]}}', false, NOW(), NOW(), '{}', 1, '1bb71da8-41d9-4c9d-98f1-779290316a76', 0, false);
INSERT INTO workflow_entity ("id", "name", "nodes", "connections", "active", "createdAt", "updatedAt", "settings", "versionCounter", "versionId", "triggerCount", "isArchived") VALUES ('88ec9823-3b4e-4f1e-8b1e-1e1e1e1e1e05', '05 — Weekly Report (Sunday Digest)', '[{"parameters": {"rule": {"interval": [{"field": "weeks", "weeksInterval": 1, "triggerAtDay": [0], "triggerAtHour": 20}]}}, "id": "t1", "name": "Sunday 20:00", "type": "n8n-nodes-base.scheduleTrigger", "typeVersion": 1.2, "position": [100, 300]}, {"parameters": {"operation": "executeQuery", "query": "SELECT count(*) as total, sum(price) as revenue FROM bookings WHERE created_at >= now() - interval ''7 days'';"}, "id": "db1", "name": "Weekly Stats", "type": "n8n-nodes-base.postgresDb", "typeVersion": 1, "position": [300, 300], "credentials": {"postgresDb": {"id": "gelendzhik_db"}}}, {"parameters": {"chatId": "-5269741256", "text": "=\ud83d\udcca *\u041e\u0442\u0447\u0435\u0442 \u0437\u0430 \u043d\u0435\u0434\u0435\u043b\u044e*\n\n\u0411\u0440\u043e\u043d\u0438\u0440\u043e\u0432\u0430\u043d\u0438\u0439: {{ $json.total }}\n\u0412\u044b\u0440\u0443\u0447\u043a\u0430: {{ $json.revenue }}\u20bd\n\n\u041f\u0440\u0438\u044f\u0442\u043d\u043e\u0433\u043e \u043e\u0442\u0434\u044b\u0445\u0430!", "additionalFields": {"parseMode": "Markdown"}}, "id": "r1", "name": "Send Owner", "type": "n8n-nodes-base.telegram", "typeVersion": 1.1, "position": [500, 300], "credentials": {"telegramApi": {"id": "telegram_owner_bot"}}}]', '{"Sunday 20:00": {"main": [[{"node": "Weekly Stats", "type": "main", "index": 0}]]}, "Weekly Stats": {"main": [[{"node": "Send Owner", "type": "main", "index": 0}]]}}', false, NOW(), NOW(), '{}', 1, '052809af-9d5c-4c40-9574-6aad23ef3e11', 0, false);
INSERT INTO workflow_entity ("id", "name", "nodes", "connections", "active", "createdAt", "updatedAt", "settings", "versionCounter", "versionId", "triggerCount", "isArchived") VALUES ('88ec9823-3b4e-4f1e-8b1e-1e1e1e1e1e06', '06 — Watchdog (System Health)', '[{"parameters": {"rule": {"interval": [{"field": "minutes", "minutesInterval": 60}]}}, "id": "t1", "name": "Every Hour", "type": "n8n-nodes-base.scheduleTrigger", "typeVersion": 1.2, "position": [100, 300]}, {"parameters": {"url": "=https://hc-ping.com/{{$env.HEALTHCHECK_ICAL_UUID}}", "options": {}}, "id": "h1", "name": "Ping Healthchecks", "type": "n8n-nodes-base.httpRequest", "typeVersion": 4.1, "position": [300, 300]}]', '{"Every Hour": {"main": [[{"node": "Ping Healthchecks", "type": "main", "index": 0}]]}}', false, NOW(), NOW(), '{}', 1, '6a3bb5c0-0818-4518-85ff-89df018fe71d', 0, false);
INSERT INTO workflow_entity ("id", "name", "nodes", "connections", "active", "createdAt", "updatedAt", "settings", "versionCounter", "versionId", "triggerCount", "isArchived") VALUES ('88ec9823-3b4e-4f1e-8b1e-1e1e1e1e1e07', '07 — Global Error Handler', '[{"parameters": {}, "id": "e1", "name": "Error Trigger", "type": "n8n-nodes-base.errorTrigger", "typeVersion": 1, "position": [100, 300]}, {"parameters": {"chatId": "-5269741256", "text": "=\ud83d\udea8 *\u041e\u0448\u0438\u0431\u043a\u0430 \u0432 \u0441\u0438\u0441\u0442\u0435\u043c\u0435 Guesthouse*\n\n\u0420\u0430\u0431\u043e\u0447\u0438\u0439 \u043f\u0440\u043e\u0446\u0435\u0441\u0441: `{{ $json.workflow.name }}`\n\u0423\u0437\u0435\u043b: `{{ $json.node.name }}`\n\u041e\u0448\u0438\u0431\u043a\u0430: `{{ $json.error.message }}`\n\n[\u041e\u0442\u043a\u0440\u044b\u0442\u044c n8n](http://192.168.1.42:5678)", "additionalFields": {"parseMode": "Markdown"}}, "id": "r1", "name": "Notify Owner", "type": "n8n-nodes-base.telegram", "typeVersion": 1.1, "position": [300, 300], "credentials": {"telegramApi": {"id": "telegram_owner_bot"}}}]', '{"Error Trigger": {"main": [[{"node": "Notify Owner", "type": "main", "index": 0}]]}}', false, NOW(), NOW(), '{}', 1, '7e456691-0d60-4179-8725-a40c5283b7ad', 0, false);
INSERT INTO workflow_entity ("id", "name", "nodes", "connections", "active", "createdAt", "updatedAt", "settings", "versionCounter", "versionId", "triggerCount", "isArchived") VALUES ('88ec9823-3b4e-4f1e-8b1e-1e1e1e1e1e08', '08 — RC Webhooks Handler', '[{"parameters": {"httpMethod": "POST", "path": "realtycalendar/webhook", "options": {}}, "id": "w1", "name": "RC Webhook", "type": "n8n-nodes-base.webhook", "typeVersion": 1, "position": [100, 300]}, {"parameters": {"conditions": {"string": [{"value1": "={{ $json.action }}", "value2": "delete_booking"}]}}, "id": "s1", "name": "Is Delete?", "type": "n8n-nodes-base.if", "typeVersion": 1, "position": [300, 300]}, {"parameters": {"operation": "executeQuery", "query": "UPDATE bookings SET status = ''deleted'' WHERE rc_id = {{ $json.data.booking.id }};"}, "id": "db1", "name": "Update DB", "type": "n8n-nodes-base.postgresDb", "typeVersion": 1, "position": [500, 400]}]', '{"RC Webhook": {"main": [[{"node": "Is Delete?", "type": "main", "index": 0}]]}}', false, NOW(), NOW(), '{}', 1, 'e2fb12cd-a6ff-4eb4-89fd-d134b7fc84e2', 0, false);
